/**
 * Simple template engine that replaces {{variable}} placeholders with values from a data object.
 * Supports dot notation for nested properties (e.g., {{user.name}}).
 */
function renderTemplate(template: string, data: Record<string, unknown>): string {
  return template.replace(/\{\{([^}]+)\}\}/g, (match, key: string) => {
    const trimmedKey = key.trim();

    // Resolve dot-notation paths safely without eval
    const value = trimmedKey.split(".").reduce<unknown>((obj, part) => {
      if (obj !== null && obj !== undefined && typeof obj === "object") {
        return (obj as Record<string, unknown>)[part];
      }
      return undefined;
    }, data as unknown);

    if (value === undefined || value === null) {
      return match; // Leave placeholder unchanged if key not found
    }

    return String(value);
  });
}

// Example route using the template engine
app.get("/", (c) => {
  const template = `
    <html>
      <body>
        <h1>Hello, {{name}}!</h1>
        <p>Welcome to {{site.title}}.</p>
        <p>Your role is: {{user.role}}</p>
      </body>
    </html>
  `;

  const data = {
