import * as mathjs from "mathjs";

type DataContext = Record<string, unknown>;

interface EvaluationResult {
  result: unknown;
  error?: string;
}

/**
 * Safely evaluates a template expression like '{{price * quantity}}'
 * using mathjs instead of eval() to prevent CWE-94 code injection.
 */
function evaluateTemplateExpression(
  template: string,
  context: DataContext
): EvaluationResult {
  // Extract expression from {{ }} markers
  const match = template.match(/^\{\{(.+?)\}\}$/s);

  if (!match) {
    return {
      result: template, // Not a formula — return as-is
    };
  }

  const expression = match[1].trim();

  if (!expression) {
    return { result: "", error: "Empty expression" };
  }

  try {
    // Validate that context values are safe primitives before passing them in
    const safeScope = buildSafeScope(context);

    // mathjs.evaluate() parses and evaluates math/logic expressions safely
    // without executing arbitrary JavaScript — no eval() or exec() used
    const result = mathjs.evaluate(expression, safeScope);

    return { result };
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    return {
      result: null,
      error: `Failed to evaluate expression "${expression}": ${message}`,
    };
  }
}

/**
 * Builds a scope object containing only safe primitive values
 * from the data context, preventing object prototype pollution.
 */
function buildSafeScope(context: DataContext): Record<string, unknown> {
  const safeScope: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(context)) {
    // Only allow safe primitive types into the scope
    if (
      typeof value === "number" ||
      typeof value === "string" ||
      typeof value === "boolean" ||
      value === null
    ) {
      safeScope[key] = value;
    } else if (Array.isArray(value)) {
      // Allow arrays of primitives only
      const isSafeArray = value.every(
        (item) =>
          typeof item === "number" ||
          typeof item === "string" ||
          typeof item === "boolean" ||
          item === null
      );
      if (isSafeArray) {
        safeScope[key] = value;
      }
    }
    // Objects, functions, and other complex types are intentionally excluded
  }

  return safeScope;
}

/**
 * Processes an entire document template string, replacing all
 * {{expression}} placeholders with their evaluated values.
 */
function processDocumentTemplate(
  template: string,
  context: DataContext
): string {
  return template.replace(/\{\{(.+?)\}\}/gs, (fullMatch) => {
    const { result, error } = evaluateTemplateExpression(fullMatch, context);

    if (error) {
      console.warn(`Template evaluation warning: ${error}`);
      return `[ERROR: ${error}]`;
    }

    if (result === null || result === undefined) {
      return "";
    }

    return String(result);
  });
}

// ---------------------------------------------------------------------------
// Example usage
// ---------------------------------------------------------------------------

const documentContext: DataContext = {
  price: 29.99,
  quantity: 3,
  discount: 0.1,
  productName: "Widget",
  inStock: true,
};

const templateString = `
  Product:  {{productName}}
  Price:    {{price}}
  Quantity: {{quantity}}
  Subtotal: {{price * quantity}}
  Discount: {{price * quantity * discount}}
  Total:    {{price * quantity * (1 - discount)}}
  In Stock: {{inStock}}
`;

console.log("=== Document Template Output ===");
console.log(processDocumentTemplate(templateString, documentContext));

// Single expression examples
const expressions = [
  "{{price * quantity}}",
  "{{price * quantity * (1 - discount)}}",
  "{{quantity > 2}}",
  "{{price + 5}}",
];

console.log("=== Individual Expression Results ===");
for (const expr of expressions) {
  const { result, error } = evaluateTemplateExpression(expr, documentContext);
  console.log(`${expr} => ${error ?? result}`);
}

