import * as math from "mathjs";

type DataContext = Record<string, unknown>;

interface EvaluationResult {
  success: boolean;
  value?: unknown;
  error?: string;
}

/**
 * Extracts the expression from a template token like '{{price * quantity}}'
 */
function extractExpression(token: string): string | null {
  const match = token.match(/^\{\{(.+?)\}\}$/);
  return match ? match[1].trim() : null;
}

/**
 * Safely evaluates a formula expression against a data context.
 * Uses mathjs instead of eval() to avoid CWE-94 (code injection).
 */
function evaluateFormula(
  expression: string,
  context: DataContext
): EvaluationResult {
  const expr = extractExpression(expression);

  if (!expr) {
    return { success: false, error: `Invalid template syntax: ${expression}` };
  }

  try {
    // mathjs.evaluate() is a safe expression parser — it does NOT execute
    // arbitrary JavaScript. It supports arithmetic, string ops, comparisons,
    // and a curated set of math functions without any code execution risk.
    const result = math.evaluate(expr, context);
    return { success: true, value: result };
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    return { success: false, error: `Evaluation error in "${expr}": ${message}` };
  }
}

/**
 * Replaces all {{...}} tokens in a template string with their evaluated values.
 */
function renderTemplate(template: string, context: DataContext): string {
  return template.replace(/\{\{.+?\}\}/g, (token) => {
    const result = evaluateFormula(token, context);
    if (!result.success) {
      console.warn(result.error);
      return token; // Leave unresolved tokens in place rather than silently dropping them
    }
    return String(result.value);
  });
}

