interface EvaluationResult {
  expression: string;
  result: number | string | boolean;
  error?: string;
}

/**
 * Extracts template expressions like {{price * quantity}} from a string.
 */
function extractExpressions(template: string): string[] {
  const regex = /\{\{([^}]+)\}\}/g;
  const expressions: string[] = [];
  let match;
  while ((match = regex.exec(template)) !== null) {
    expressions.push(match[1].trim());
  }
  return expressions;
}

/**
 * Safely evaluates a single math/logic expression using mathjs.
 * Variables are substituted from the provided data context.
 */
function evaluateExpression(
  expression: string,
  data: DocumentData
): EvaluationResult {
  try {
    // Build a mathjs scope from the document data
    const scope: Record<string, number | string | boolean> = {};

    for (const [key, value] of Object.entries(data)) {
      // Only allow safe variable names (alphanumeric + underscore)
      if (/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(key)) {
        scope[key] = value;
      }
    }

    // mathjs.evaluate is a safe, sandboxed expression evaluator — no eval() used
    const result = math.evaluate(expression, scope);

    // Ensure result is a primitive we can work with
    if (
      typeof result !== "number" &&
      typeof result !== "string" &&
      typeof result !== "boolean"
    ) {
      throw new Error(`Unsupported result type: ${typeof result}`);
    }

    return { expression, result };
  } catch (err) {
    return {
      expression,
      result: "",
      error: err instanceof Error ? err.message : "Unknown evaluation error",
    };
  }
