function evaluateFormula(expression: string, data: DocumentData): string {
  // Extract content between {{ and }}
  const formulaMatch = expression.match(/^\{\{(.+)\}\}$/);
  if (!formulaMatch) {
    return expression;
  }

  const formula = formulaMatch[1].trim();

  // Build variable declarations from document data using JSON.parse for safety
  const varDeclarations = Object.entries(data)
    .map(([key, value]) => {
      // Use JSON.parse to safely handle the value
      const safeValue = JSON.parse(JSON.stringify(value));
      if (typeof safeValue === "string") {
        return `const ${key} = ${JSON.stringify(safeValue)};`;
      }
      return `const ${key} = ${safeValue};`;
    })
    .join("\n");

  const code = `${varDeclarations}\n${formula}`;

