// Document data context type
type DocumentContext = Record<string, unknown>;

/**
 * Evaluates a formula expression from a document template.
 * Extracts the expression from '{{...}}' syntax and evaluates it
 * using the provided document data context.
 */
function evaluateFormula(
  expression: string,
  context: DocumentContext
): unknown {
  // Extract the formula from '{{...}}' syntax
  const match = expression.match(/^\{\{(.+)\}\}$/s);
  if (!match) {
    throw new Error(
      `Invalid formula syntax: expected '{{expression}}', got '${expression}'`
    );
  }

  const formula = match[1].trim();

  // Build a function that has the context variables in scope
  const contextKeys = Object.keys(context);
  const contextValues = contextKeys.map((key) => context[key]);

  // Use Function constructor to evaluate the formula with context variables in scope
  // eslint-disable-next-line no-new-func
  const evaluator = new Function(...contextKeys, `return (${formula});`);

  return evaluator(...contextValues);
}

/**
 * Processes a document template string, replacing all '{{...}}' formulas
 * with their evaluated results.
 */
function processTemplate(
  template: string,
  context: DocumentContext
): string {
  return template.replace(/\{\{(.+?)\}\}/gs, (match) => {
    const result = evaluateFormula(match, context);
    return String(result);
  });
}

