 * Extracts the inner expression from a template placeholder like '{{price * quantity}}'
 */
function extractExpression(template: string): string | null {
  const match = template.match(/^\{\{(.+?)\}\}$/);
  return match ? match[1].trim() : null;
}

/**
 * Resolves variable names in an expression to their values from the data context.
 * Only allows safe identifier characters (letters, digits, underscore).
 */
function resolveVariables(
  expression: string,
  data: DocumentData
): { resolved: string; usedVars: string[] } {
  const usedVars: string[] = [];

  // Match identifiers that are keys in the data object
  const resolved = expression.replace(/\b([a-zA-Z_][a-zA-Z0-9_]*)\b/g, (match) => {
    if (Object.prototype.hasOwnProperty.call(data, match)) {
      usedVars.push(match);
      const value = data[match];
      if (typeof value === "string") {
        // Wrap strings in quotes for mathjs
        return JSON.stringify(value);
      }
      return String(value);
    }
    return match; // leave unknown identifiers for mathjs to handle (e.g., built-in constants)
